package main

import "fmt"

func shift(input string, distance byte) string {
	output := []byte(input)
	for index, value := range output {
		if value >= 'A' && value <= 'Z' { output[index] = 'A' + (value-'A'+distance)%26 }
	}
	return string(output)
}

func main() {
	ciphertext := shift("MEETATNOON", 2)
	fmt.Printf("ciphertext=%s recovered=%s production=false\n", ciphertext, shift(ciphertext, 26-2))
}

